from __future__ import annotationsimport jsonimport osfrom langchain_core.messages import HumanMessage, SystemMessage, ToolMessagefrom langchain_google_genai import ChatGoogleGenerativeAIfrom app.agents.profiler.base import IndexedRecord, LayerB, ProfilerAnalysisOutputfrom app.agents.profiler.subagent.profiler_agent.investigation import (    build_investigation_evidence,    evidence_json_sections,    merge_tool_results,)from app.agents.profiler.subagent.profiler_agent.prompt import (    PROFILER_AGENT_SYSTEM_PROMPT,    PROFILER_ANALYSIS_HUMAN_TEMPLATE,)from app.agents.profiler.subagent.profiler_agent.tools import build_investigation_toolsfrom app.agents.profiler.subagent.scoring import (    fallback_analysis,    filter_search_records,    filter_watch_records,)DEFAULT_GEMINI_MODEL = "gemini-2.5-flash"MAX_TOOL_ITERATIONS = 1INVESTIGATION_SYSTEM_PROMPT = """\You are the Profiler investigation agent for Synapse 8 user profiling.In your FIRST and ONLY response, call ALL four tools in parallel:get_channel_breakdown, get_search_queries, get_tag_distribution, get_sample_records.Do not finish without calling every tool."""def get_gemini_api_key() -> str | None:    return os.getenv("GOOGLE_API_KEY") or os.getenv("GEMINI_API_KEY")def get_gemini_model() -> str:    return os.getenv("GEMINI_MODEL", DEFAULT_GEMINI_MODEL)def _tool_result_content(result: object) -> str:    if isinstance(result, str):        return result    return json.dumps(result, ensure_ascii=False)def run_llm_analysis(    user_id: str,    records: list[IndexedRecord],    layer_b: LayerB,    investigation_log: list[str],) -> ProfilerAnalysisOutput:    api_key = get_gemini_api_key()    if not api_key:        return fallback_analysis(user_id, records, layer_b, investigation_log)    tools = build_investigation_tools(records)    tool_by_name = {tool.name: tool for tool in tools}    model = ChatGoogleGenerativeAI(        model=get_gemini_model(),        temperature=0.2,        google_api_key=api_key,    )    llm_with_tools = model.bind_tools(tools)    watch_count = len(filter_watch_records(records))    search_count = len(filter_search_records(records))    messages = [        SystemMessage(content=INVESTIGATION_SYSTEM_PROMPT),        HumanMessage(            content=(                f"user_id={user_id}\n"                f"record_summary: total={len(records)}, "                f"watch={watch_count}, search={search_count}\n"                f"layer_b={layer_b.model_dump_json()}\n"                "Call all four investigation tools now."            )        ),    ]    investigation_log.append("agent: llm_tool_loop_start")    collected_tool_results: dict[str, str] = {}    for _ in range(MAX_TOOL_ITERATIONS):        ai_message = llm_with_tools.invoke(messages)        messages.append(ai_message)        tool_calls = getattr(ai_message, "tool_calls", None) or []        if not tool_calls:            investigation_log.append("agent: tool_loop_no_calls")            break        for tool_call in tool_calls:            name = tool_call["name"]            tool = tool_by_name.get(name)            if tool is None:                content = f"unknown tool: {name}"            else:                content = _tool_result_content(tool.invoke(tool_call.get("args") or {}))            collected_tool_results[name] = content            investigation_log.append(f"tool:{name}")            messages.append(ToolMessage(content=content, tool_call_id=tool_call["id"]))    investigation_log.append("agent: tool_loop_complete")    evidence = merge_tool_results(        build_investigation_evidence(records),        collected_tool_results,    )    if not collected_tool_results:        investigation_log.append("agent: evidence_backfill")    sections = evidence_json_sections(evidence)    human = PROFILER_ANALYSIS_HUMAN_TEMPLATE.format(        user_id=user_id,        layer_b_json=layer_b.model_dump_json(indent=2),        investigation_log="\n".join(f"- {line}" for line in investigation_log),        record_summary=(            f"total={len(records)}, watch={watch_count}, search={search_count}"        ),        channel_breakdown=sections["channel_breakdown"],        search_queries=sections["search_queries"],        tag_distribution=sections["tag_distribution"],        sample_records=sections["sample_records"],    )    final_messages = [        SystemMessage(content=PROFILER_AGENT_SYSTEM_PROMPT),        HumanMessage(content=human),    ]    structured = model.with_structured_output(ProfilerAnalysisOutput)    result = structured.invoke(final_messages)    if isinstance(result, ProfilerAnalysisOutput):        return result    return ProfilerAnalysisOutput.model_validate(result)